mapper.select:

from seller s

where s.seller_code = #{sellerCode}
limit 1

mapper.insert:
insert into seller_account(
    seller_id, dept_id, user_name, nick_name, password, email, phonenumber,
    account_role, status, pwd_update_time, create_by, create_time, remark
) values (
    #{sellerId}, #{deptId}, #{userName}, #{nickName}, #{password}, #{email}, #{phonenumber},
    #{accountRole}, #{status}, sysdate(), #{createBy}, sysdate(), #{remark}
)

insert into seller_login_log(
    seller_id, seller_account_id, user_name, ipaddr, login_location,
    browser, os, status, msg, login_time
) values (
    #{subjectId}, #{accountId}, #{userName}, #{ipaddr}, #{loginLocation},
    #{browser}, #{os}, #{status}, #{msg}, #{loginTime}
)

mapper.select:
select l.info_id, l.seller_id, l.seller_account_id, l.user_name, l.ipaddr, l.login_location, l.browser, l.os, l.status, l.msg, l.login_time from seller_login_log l where 1 = 1
and l.seller_id = #{subjectId}
and l.seller_account_id = #{accountId}
and l.user_name like concat('%', #{userName}, '%')
and l.ipaddr like concat('%', #{ipaddr}, '%')
and l.status = #{status}
and date_format(l.login_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')
and date_format(l.login_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')
order by l.login_time desc, l.info_id desc

select l.oper_id, l.seller_id, l.seller_account_id, l.title, l.business_type, l.method, l.request_method, l.oper_name, l.oper_url, l.oper_ip, l.oper_location, l.oper_param, l.json_result, l.status, l.error_msg, l.oper_time, l.cost_time from seller_oper_log l where 1 = 1
and l.seller_id = #{subjectId}
and l.seller_account_id = #{accountId}
and l.title like concat('%', #{title}, '%')
and l.oper_name like concat('%', #{operName}, '%')
and l.status = #{status}
and date_format(l.oper_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')
and date_format(l.oper_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')
order by l.oper_time desc, l.oper_id desc

mapper.insert:
insert into seller_session(
    token_id, seller_id, seller_account_id, user_name,
    login_ip, login_time, expire_time, status
) values (
    #{tokenId}, #{subjectId}, #{accountId}, #{userName},
    #{loginIp}, #{loginTime}, #{expireTime}, #{status}
)

mapper.select:
select token_id as tokenId, 'seller' as terminal, seller_id as subjectId, seller_account_id as accountId, user_name as userName, login_ip as loginIp, login_time as loginTime, expire_time as expireTime, logout_time as logoutTime, status from seller_session where seller_id = #{sellerId}
and seller_account_id = #{sellerAccountId}
order by login_time desc, token_id desc

select count(1)
from seller_session
where seller_id = #{sellerId}
  and seller_account_id = #{sellerAccountId}
  and token_id = #{tokenId}
  and status = '0'
  and logout_time is null
  and expire_time >= sysdate()

mapper.update:
update seller_session
set status = '1',
    logout_time = sysdate()
where seller_id = #{sellerId}
  and seller_account_id = #{sellerAccountId}
  and token_id = #{tokenId}
  and status = '0'
  and logout_time is null
